function ModelQuestion:OnModelInit()

    self._webQuestionData = {}


    self:ModelNetMsgRecv(LProtoIds.QuestionnaireAnswerResp,function (...)
        self:OnQuestionnaireAnswerResp(...)
    end)

    self:ModelNetMsgRecv(LProtoIds.QuestionnaireRewardResp,function (...)
        self:OnQuestionnaireRewardResp(...)
    end)
end

--在协议数据处理完之后需要调用finish
function ModelQuestion:OnModelRequest()
