function ModelQuestion:OnQuestionnaireAnswerReq(data,sid,questId)
    local pb = LProtoHelper.CreateProto(LProtoIds.QuestionnaireAnswerReq)
    pb.data = data
    pb.id = questId
    pb.refId = sid
    SendMessage(pb,LProtoIds.QuestionnaireAnswerReq)
end

function ModelQuestion:OnQuestionnaireRewardReq(sid)
    local pb = LProtoHelper.CreateProto(LProtoIds.QuestionnaireRewardReq)
    pb.sid = sid
    SendMessage(pb,LProtoIds.QuestionnaireRewardReq)
end

function ModelQuestion:GetWebQuestionData(qid)
    local webData = self._webQuestionData[qid]

    if not webData or webData:IsDestroy() then
        webData = LWebQuestionData:New()
        self._webQuestionData[qid] = webData
        webData:InitFirstData(qid)

        if webData:StartInitWebData() then
            return webData
        end
    else
        if not webData:IsOk() then
            return
        end

        return webData
    end
end

function ModelQuestion:ReqWebQuestionData(qid)
    local data = self:GetWebQuestionData(qid)
    if data then
        FireEvent(EventNames.ON_QUESTION_CONFIG_DATA,qid,data)
    end
end

function ModelQuestion:GetQuestionShowData(mainId)
    local webData = self:GetWebQuestionData(mainId)
    if not webData then
        return
    end

    local data = webData:GetFormatData()

    local showData = {
        mainData= data.mainData,
    }

    local showlist = {}
    for k,v in pairs(data.questionMap) do
        if self:CheckIsShow(data.mainData.id,v) then
            table.insert(showlist,v)
        end
    end

    table.sort(showlist,function (a,b)
        return a.id <b.id
    end)
    showData.showlist = showlist
    return showData
end

function ModelQuestion:CheckIsShow(mainId,questdata)
    if not questdata.associations or #questdata.associations == 0 then
        return true
    end
    local isAnd = questdata.associateRelation == "andRelation"

    for k,v in ipairs(questdata.associations) do
        local questId = tonumber(v.associateId)
        local value = v.associateVal
        local temp = self:CheckIsFill(mainId,questId,value)
        if isAnd then
            if not temp then
                return false
            end
        else
            if temp then
                return true
            end
        end
    end

    if isAnd then
        return true
    else
        return false
    end
end

function ModelQuestion:CheckIsFill(mainId,questId,value)
    local answer = self:GetAnswer(mainId,questId)
    if not answer then
        return false
    end

    local questData = self:GetQuestionData(mainId,questId)
    if not questData then
        return false
    end

    local isFill = false
    if questData.type == ModelQuestion.SELECT then
        local option = answer[value]
        isFill = option and option.isCheck
    elseif questData.type == ModelQuestion.RATE then
        isFill = tonumber(value)<= answer.star
    end

    return isFill
end

function ModelQuestion:GetQuestionData(mainId,questId)
    local webData = self._webQuestionData and self._webQuestionData[mainId]
    if not webData then
        return
    end

    local questdata = webData:GetQuestionData(questId)
    return questdata
end

---选择题答案结构{["A"]={isCheck = true, content = ""},}
---评分题答案{star=1}
---文本题答案{content=""}
---填空题答案{[1]={content=""},}
function ModelQuestion:SaveAnswer(mainId,questId,value)
    if not self._answerMap then
        self._answerMap = {}
    end

    local answerData = self._answerMap[mainId]
    if not answerData then
        answerData = {}
        self._answerMap[mainId] = answerData
    end
    answerData[questId] = value
end

function ModelQuestion:GetAnswer(mainId,questId)
    if not self._answerMap then
        return
    end
    local answerData = self._answerMap[mainId]
    if not answerData then
        return
    end

    return answerData[questId]
end

function ModelQuestion:CheckCanSubmit(mainId)
    local questData = self:GetQuestionShowData(mainId)
    for k,v in ipairs(questData.showlist) do
        if v.necessary then
            local isFinish = self:IsQuestFinish(mainId,v.id)
            if not isFinish then
                return false,k
            end
        end
    end
    return true
end

function ModelQuestion:IsQuestFinish(mainId,questId)
    local questData = self:GetQuestionData(mainId,questId)
    if not questData then
        return false
    end
    local answer = self:GetAnswer(mainId,questId)
    if not answer then
        return false
    end

    local type = questData.type
    if type == ModelQuestion.SELECT or type == ModelQuestion.SELECT_PIC then
        for k,v in ipairs(questData.selectList) do

        end
        for k,v in pairs(answer) do
            if v.isCheck then
                return true
            end
        end
    elseif type == ModelQuestion.INPUT then
        if not string.isempty(answer.content) then
            return true
        end

    elseif type == ModelQuestion.RATE or type == ModelQuestion.RATE_PIC then
        if answer.star and answer.star>0 then
            return true
        end

    elseif type == ModelQuestion.FILL then
        local isAllFill = true
        for k,v in ipairs(questData.fillList) do
            local index = v.index
            local content = answer[index]
            if string.isempty(content) then
                isAllFill = false
                break
            end
        end

        if isAllFill then
            return true
        end
    end

    return false
end

function ModelQuestion:SendQuestionData(mainId,sid)

    local answerMap = {}
    local questData = self:GetQuestionShowData(mainId)
    for k,v in ipairs(questData.showlist) do
        local answer = self:GetAnswer(mainId,v.id)
        if answer then
            local tempData = {}
            tempData.questionId = v.id
            tempData.answer = {}
            if v.type == ModelQuestion.SELECT or v.type == ModelQuestion.SELECT_PIC then

                for k1,v1 in pairs(answer) do
                    if v1.isCheck then
                        local option = {
                            name = k1,
                            content = v1.content
                        }

                        table.insert(tempData.answer,option)
                    end
                end
            elseif v.type == ModelQuestion.RATE or v.type == ModelQuestion.RATE_PIC then
                local temp=
                {
                    content = tostring(answer.star)
                }
                table.insert(tempData.answer,temp)
            elseif v.type == ModelQuestion.INPUT then
                local temp=
                {
                    content = answer.content
                }
                table.insert(tempData.answer,temp)
            elseif v.type == ModelQuestion.FILL then
                local tempList = {}
                for k1,v1 in pairs(answer) do
                    local fillItem = {
                        name = k1,
                        content = v1.content
                    }
                    table.insert(tempList,fillItem)
                end

                table.sort(tempList,function (a,b)
                    return a.name< b.name
                end)

                for k1,v1 in ipairs(tempList) do
                    table.insert(tempData.answer,{content = v1.content})
                end
            end

            table.insert(answerMap,tempData)
        end
    end


    local dataJson = JSON.encode(answerMap)

    self:OnQuestionnaireAnswerReq(dataJson,sid,mainId)

end

